// ============================================================
// STORAGE (with in-memory fallback) — same shape as other artifacts
// ============================================================
const memStore = {};
let useMemFallback = false;
const storage = {
  async get(key) {
    if (useMemFallback) return memStore[key] !== undefined ? memStore[key] : null;
    try {
      const r = await window.storage.get(key);
      if (!r) return null;
      if (typeof r.value === "string") {
        try { return JSON.parse(r.value); } catch { return r.value; }
      }
      return r.value;
    } catch { return null; }
  },
  async set(key, value) {
    if (useMemFallback) { memStore[key] = value; return true; }
    try { await window.storage.set(key, JSON.stringify(value)); return true; }
    catch (e) { useMemFallback = true; memStore[key] = value; return true; }
  },
  async list(prefix) {
    if (useMemFallback) return Object.keys(memStore).filter(k => k.startsWith(prefix || ""));
    try { const r = await window.storage.list(prefix); return r?.keys || []; } catch { return []; }
  },
};
const userKey = (id, k) => `u:${id}:${k}`;

