function buildLogs(c) {
  const t = calculateTargets(c.profile);
  const total = c.we - c.ws;
  const logs = {};
  for (let dayBack = 41; dayBack >= 0; dayBack--) {
    const date = dateNDaysAgo(dayBack);
    const progress = (41 - dayBack) / 41;
    const baseWeight = c.ws + total * progress;
    const noise = (srand(c.seed + dayBack) - 0.5) * 0.6;
    const weight = Math.round((baseWeight + noise) * 10) / 10;
    const r = srand(c.seed + dayBack * 7);
    if (r < 0.1) { logs[date] = { food: false, kcalEaten: 0, proteinEaten: 0, fatEaten: 0, carbsEaten: 0, weight: false, weightValue: 0 }; continue; }
    const kcal = c.kc + Math.round((srand(c.seed + dayBack * 11) - 0.5) * 400);
    const protein = Math.round(t.protein + (srand(c.seed + dayBack * 13) - 0.5) * 20);
    const fat = Math.round(t.fat + (srand(c.seed + dayBack * 17) - 0.5) * 15);
    const carbs = Math.round((kcal - 4 * protein - 9 * fat) / 4);
    logs[date] = { food: true, kcalEaten: kcal, proteinEaten: protein, fatEaten: Math.max(20, fat), carbsEaten: Math.max(50, carbs), steps: true, stepsTaken: 8000 + Math.floor(srand(c.seed + dayBack * 19) * 4000), weight: true, weightValue: weight, workout: dayBack % 2 === 0 };
  }
  return logs;
}

function buildLiftHistory(c) {
  const lifts = {};
  for (const [exName, exData] of Object.entries(c.lifts)) {
    const sessions = [];
    const isStalled = exData.stalled === true;
    for (let s = 7; s >= 1; s--) {
      const sessionDate = dateNDaysAgo(s * 4);
      const growthFactor = isStalled ? 0.05 : exData.growth;
      const sessionWeight = exData.startWeight + growthFactor * (8 - s);
      const roundedWeight = exData.startWeight === 0 ? 0 : Math.round(sessionWeight / 2.5) * 2.5;
      const targetReps = exData.reps;
      const sets = [];
      for (let i = 0; i < 3; i++) {
        const repAdjust = isStalled ? -1 : 0;
        const reps = Math.max(1, targetReps - i + repAdjust + Math.floor(srand(c.seed + s * 31 + i) * 2));
        const rir = Math.floor(srand(c.seed + s * 37 + i) * 3);
        sets.push({ weight: roundedWeight, reps, rir });
      }
      sessions.push({ date: sessionDate, sets });
    }
    const latest = sessions[sessions.length - 1];
    lifts[exName] = { lastSession: latest.sets, lastDate: latest.date, history: sessions };
  }
  return lifts;
}

