// ============================================================
// CALC HELPERS
// ============================================================
function calculateTargets({ sex, age, dob, height, weight, activity, goal }) {
  if (!age && dob) { const b = new Date(dob); const n = new Date(); age = n.getFullYear() - b.getFullYear(); if (n.getMonth() < b.getMonth() || (n.getMonth() === b.getMonth() && n.getDate() < b.getDate())) age--; }
  age = age || 30;
  const w = weight || 1;
  const bmr = sex === "M" ? 10 * w + 6.25 * height - 5 * age + 5 : 10 * w + 6.25 * height - 5 * age - 161;
  return { tdee: Math.round(bmr * activity) };
}

// Brzycki 1RM: weight × (36 / (37 - reps))
function estimate1RM(weight, reps) {
  if (!weight || !reps || reps >= 37) return 0;
  return Math.round((weight * (36 / (37 - reps))) * 10) / 10;
}

// Linear regression for trend projection: returns { slope, intercept, projection }
function linearTrend(points) {
  if (points.length < 2) return { slope: 0, intercept: points[0]?.y || 0 };
  const n = points.length;
  const sumX = points.reduce((s, p) => s + p.x, 0);
  const sumY = points.reduce((s, p) => s + p.y, 0);
  const sumXY = points.reduce((s, p) => s + p.x * p.y, 0);
  const sumXX = points.reduce((s, p) => s + p.x * p.x, 0);
  const slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX) || 0;
  const intercept = (sumY - slope * sumX) / n;
  return { slope, intercept };
}

// Pearson correlation between two arrays
function correlation(xs, ys) {
  if (xs.length < 3 || xs.length !== ys.length) return 0;
  const n = xs.length;
  const mx = xs.reduce((a, b) => a + b, 0) / n;
  const my = ys.reduce((a, b) => a + b, 0) / n;
  let num = 0, dx = 0, dy = 0;
  for (let i = 0; i < n; i++) {
    const ax = xs[i] - mx, ay = ys[i] - my;
    num += ax * ay; dx += ax * ax; dy += ay * ay;
  }
  const denom = Math.sqrt(dx * dy);
  return denom === 0 ? 0 : num / denom;
}

// Map exercise to muscle group (kept simple for analytics — match library)
const MUSCLE_MAP = {
  "Barbell Bench Press": "Chest", "Dumbbell Bench Press": "Chest", "Machine Chest Press": "Chest",
  "Incline Dumbbell Press": "Chest", "Cable Fly": "Chest", "Push-ups": "Chest",
  "Barbell Row": "Back", "Dumbbell Row": "Back", "Lat Pulldown": "Back", "Pull-ups": "Back",
  "Cable Row": "Back", "Face Pull": "Back",
  "Barbell Squat": "Legs", "Goblet Squat": "Legs", "Leg Press": "Legs", "Hack Squat": "Legs",
  "Bulgarian Split Squat": "Legs", "Lunges": "Legs", "Leg Extension": "Legs",
  "Romanian Deadlift": "Hamstrings", "DB Romanian Deadlift": "Hamstrings", "Hamstring Curl": "Hamstrings",
  "Standing Calf Raise": "Calves",
  "Overhead Press": "Shoulders", "Dumbbell Shoulder Press": "Shoulders",
  "Machine Shoulder Press": "Shoulders", "Lateral Raise": "Shoulders", "Cable Lateral Raise": "Shoulders",
  "Barbell Curl": "Biceps", "Dumbbell Curl": "Biceps", "Cable Curl": "Biceps", "Hammer Curl": "Biceps",
  "Tricep Pushdown": "Triceps", "Skull Crushers": "Triceps", "Overhead Tricep Extension": "Triceps",
  "Plank": "Core", "Hanging Leg Raise": "Core", "Cable Crunch": "Core",
};

// Optimal weekly set ranges per muscle group (textbook hypertrophy guidance for unlimited time)
const OPTIMAL_VOLUME = {
  "Chest": [10, 18], "Back": [10, 20], "Legs": [10, 18], "Hamstrings": [6, 12],
  "Shoulders": [8, 16], "Biceps": [8, 14], "Triceps": [8, 14], "Core": [6, 16],
  "Calves": [8, 16],
};

// Minimum effective dose — even with very limited capacity, this is the floor
// below which a muscle group probably won't grow.
const MIN_EFFECTIVE_DOSE = 4;

// Estimate working sets achievable per minute of session time. 0.4 ≈ one set
// every 2.5 minutes (set + rest + transition). A 45-min session ≈ 18 working sets.
const SETS_PER_MINUTE = 0.4;

// Maps profile focusAreas labels to MUSCLE_MAP categories.
// Focus labels in onboarding are user-friendly; here we translate to volume keys.
const FOCUS_TO_MUSCLES = {
  "Glutes": ["Legs", "Hamstrings"],
  "Core": ["Core"],
  "Chest": ["Chest"],
  "Arms": ["Biceps", "Triceps"],
  "Shoulders": ["Shoulders"],
  "Back": ["Back"],
  "Legs": ["Legs", "Hamstrings", "Calves"],
};

/**
 * Returns a goal multiplier that biases volume targets up or down.
 * - Cut: 0.75 (preserve, don't try to grow much — tissue gain unlikely in deficit)
 * - Recomp: 0.9 (slight reduction)
 * - Maintain: 1.0 (full hypertrophy targets)
 * - Lean Bulk / Bulk: 1.0 (full targets — not higher; more isn't better above the textbook upper)
 */
function goalMultiplier(profile) {
  const goal = (profile?.goal || "").toLowerCase();
  if (goal.includes("cut") || goal.includes("loss")) return 0.75;
  if (goal.includes("recomp")) return 0.9;
  return 1.0;
}

/**
 * Scales the textbook OPTIMAL_VOLUME ranges to fit a user's actual weekly
 * training capacity, derived from their planned days and session length.
 * Also applies goal multiplier (cuts get lower targets) and focus bias
 * (focus muscles get +25%, non-focus get -10% redistribution).
 *
 * Returns: { ranges: { muscle: [min, max] }, capacity, textbookTotal, scalingFactor, goalMult, focusMuscles }
 */
function getScaledOptimalVolume(profile) {
  const daysPerWeek = (profile && profile.daysPerWeek) || 4;
  const sessionLength = (profile && profile.sessionLength) || 60;
  const weeklyCapacity = daysPerWeek * sessionLength * SETS_PER_MINUTE;

  const textbookTotal = Object.values(OPTIMAL_VOLUME).reduce((sum, [, hi]) => sum + hi, 0);
  // We compare capacity to the *upper* bound of textbook so a 6-day/60-min user (capacity 144)
  // gets a factor close to 1 (they can hit textbook tops). Anyone less gets scaled down.
  const baseScaling = Math.min(1, weeklyCapacity / textbookTotal);
  const goalMult = goalMultiplier(profile);
  const scalingFactor = baseScaling * goalMult;

  // Resolve focus muscles from profile.focusAreas
  const focusMuscles = new Set();
  for (const area of profile?.focusAreas || []) {
    const muscles = FOCUS_TO_MUSCLES[area] || [];
    muscles.forEach(m => focusMuscles.add(m));
  }

  const ranges = {};
  for (const [muscle, [lo, hi]] of Object.entries(OPTIMAL_VOLUME)) {
    // Focus bias: +25% on focus muscles, -10% on non-focus (only if user has any focus areas set)
    const focusBias = focusMuscles.size > 0
      ? (focusMuscles.has(muscle) ? 1.25 : 0.9)
      : 1.0;
    const factor = scalingFactor * focusBias;
    const scaledLo = Math.max(MIN_EFFECTIVE_DOSE, Math.round(lo * factor));
    const scaledHi = Math.max(scaledLo + 1, Math.round(hi * factor));
    ranges[muscle] = [scaledLo, scaledHi];
  }
  return { ranges, weeklyCapacity, textbookTotal, scalingFactor, goalMult, focusMuscles: Array.from(focusMuscles) };
}

