function Overview({ profile, logs, lifts, blocks, completions, theme, onJump }) {
  const stats = useMemo(() => computeOverviewStats(profile, logs, lifts, completions), [profile, logs, lifts, completions]);
  const insights = useMemo(() => generateInsights(profile, logs, lifts, completions, blocks), [profile, logs, lifts, completions, blocks]);

  // Pick top exercise for the strength chart
  const topExercise = useMemo(() => {
    const candidates = ["Barbell Bench Press", "Barbell Squat", "Barbell Row", "Romanian Deadlift", "Overhead Press"];
    return candidates.find(e => lifts[e]?.history?.length >= 3) || Object.keys(lifts)[0];
  }, [lifts]);

  return (
    <>
      {/* 4 KPI cards */}
      <div className="grid grid-cols-2 gap-2">
        <KpiCard label="Performance Score" value={`${stats.performanceScore}`} unit="/100" delta={stats.scoreDelta} accent={ORANGE} ring={stats.performanceScore} theme={theme} />
        <KpiCard label="Strength Trend" value={stats.strengthTrend.label} sub={stats.strengthTrend.sub} accent={stats.strengthTrend.accent} mini={stats.strengthTrend.mini} theme={theme} />
        <KpiCard label="Adherence" value={`${stats.adherence}%`} sub="logged days/window" accent={stats.adherence >= 70 ? GREEN : stats.adherence >= 40 ? ORANGE : RED} mini={stats.adherenceMini} theme={theme} />
        <KpiCard label="Consistency" value={`${stats.consistency}%`} delta={stats.consistencyDelta} sub="last 4 wks" accent={stats.consistency >= 70 ? GREEN : ORANGE} theme={theme} />
      </div>

      {/* Strength preview */}
      {topExercise && (
        <div className={`${theme.card} rounded-2xl border ${theme.border} p-4`}>
          <div className="flex items-center justify-between mb-3">
            <div className="text-[10px] font-bold uppercase tracking-wide flex items-center gap-1" style={{ color: theme.textMuted.includes("400") ? "#94a3b8" : "#64748b" }}>
              Strength Progress
            </div>
            <button onClick={() => onJump("strength")} className="text-[10px] font-semibold flex items-center gap-1" style={{ color: ORANGE }}>
              All exercises →
            </button>
          </div>
          <StrengthMiniChart exerciseName={topExercise} lifts={lifts} theme={theme} />
        </div>
      )}

      {/* AI Insights strip */}
      <InsightsStrip insights={insights} theme={theme} />
    </>
  );
}

function KpiCard({ label, value, unit, sub, delta, accent, ring, mini, theme }) {
  return (
    <div className={`${theme.card} rounded-2xl border ${theme.border} p-3 relative overflow-hidden`}>
      <div className="text-[10px] font-medium" style={{ color: theme.textMuted.includes("400") ? "#94a3b8" : "#64748b" }}>{label}</div>
      <div className="flex items-baseline gap-1 mt-1">
        <div className={`text-2xl font-bold ${theme.text}`}>{value}</div>
        {unit && <div className={`text-xs ${theme.textMuted}`}>{unit}</div>}
      </div>
      {ring !== undefined && (
        <div className="absolute top-2.5 right-2.5">
          <svg viewBox="0 0 36 36" width="32" height="32" className="-rotate-90">
            <circle cx="18" cy="18" r="14" fill="none" stroke={theme.bg.includes("black") ? "#1e293b" : "#e2e8f0"} strokeWidth="3" />
            <circle cx="18" cy="18" r="14" fill="none" stroke={accent} strokeWidth="3"
              strokeDasharray={`${(ring / 100) * 87.96} 87.96`} strokeLinecap="round" />
          </svg>
        </div>
      )}
      {mini && (
        <div className="mt-2">
          <Sparkline data={mini} color={accent} width={140} height={28} theme={theme} />
        </div>
      )}
      {delta !== undefined && delta !== 0 && (
        <div className="text-[10px] font-bold mt-1 flex items-center gap-0.5" style={{ color: delta > 0 ? GREEN : RED }}>
          {delta > 0 ? "▲" : "▼"} {Math.abs(delta).toFixed(0)}%
          <span className={`font-medium ml-1 ${theme.textMuted}`}>vs last 4 wks</span>
        </div>
      )}
      {sub && delta === undefined && <div className={`text-[10px] ${theme.textMuted} mt-0.5`}>{sub}</div>}
    </div>
  );
}

function Sparkline({ data, color, width = 100, height = 30, theme }) {
  if (!data || data.length < 2) return null;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const pts = data.map((v, i) => {
    const x = (i / (data.length - 1)) * width;
    const y = height - ((v - min) / range) * height;
    return `${x},${y}`;
  }).join(" ");
  // Area fill
  const areaPoints = `0,${height} ${pts} ${width},${height}`;
  return (
    <svg viewBox={`0 0 ${width} ${height}`} width="100%" height={height}>
      <polygon fill={color} fillOpacity="0.15" points={areaPoints} />
      <polyline fill="none" stroke={color} strokeWidth="1.5" points={pts} />
    </svg>
  );
}

