function StrengthTab({ profile, lifts, theme }) {
  const trackedExercises = useMemo(() => Object.entries(lifts)
    .filter(([_, data]) => data?.history?.length >= 2)
    .sort((a, b) => (b[1].history?.length || 0) - (a[1].history?.length || 0))
    .map(([name]) => name), [lifts]);

  const [selected, setSelected] = useState(trackedExercises[0]);

  useEffect(() => {
    if (!selected && trackedExercises[0]) setSelected(trackedExercises[0]);
  }, [trackedExercises, selected]);

  if (!trackedExercises.length) {
    return <EmptyState title="No lift history yet" sub="Log workouts in the training app to see strength progression." theme={theme} />;
  }

  return (
    <>
      {/* Exercise picker */}
      <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`}>
        <div className="flex items-center justify-between mb-2">
          <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted}`}>Exercise</div>
          <div className={`text-[10px] ${theme.textMuted}`}>{trackedExercises.length} tracked</div>
        </div>
        <div className="overflow-x-auto -mx-1 px-1">
          <div className="flex gap-1.5 pb-1">
            {trackedExercises.map(ex => (
              <button key={ex} onClick={() => setSelected(ex)}
                className="px-3 h-10 rounded-lg font-semibold text-xs whitespace-nowrap flex-shrink-0"
                style={{ backgroundColor: selected === ex ? NAVY : "", color: selected === ex ? "white" : "" }}>
                <div className={selected === ex ? "" : `${theme.surface} ${theme.surfaceText} h-full px-2 -mx-3 flex items-center rounded-lg`}>{ex}</div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {selected && <StrengthDetail exerciseName={selected} lifts={lifts} theme={theme} />}
    </>
  );
}

function StrengthDetail({ exerciseName, lifts, theme }) {
  const data = lifts[exerciseName];
  if (!data?.history) return null;

  // Compute estimated 1RM for each session (best set = highest e1RM)
  const series = data.history.map(s => {
    const best1RM = s.sets.reduce((max, set) => Math.max(max, estimate1RM(set.weight, set.reps)), 0);
    const bestSet = s.sets.reduce((b, set) => estimate1RM(set.weight, set.reps) > estimate1RM(b.weight, b.reps) ? set : b, s.sets[0]);
    return { date: s.date, value: best1RM, bestSet };
  });

  const current = series[series.length - 1];
  const fourWeeksAgo = series.find(s => {
    const d = new Date(s.date);
    return Math.abs(Date.now() - d.getTime()) >= 25 * 86400000 && Math.abs(Date.now() - d.getTime()) <= 35 * 86400000;
  }) || series[Math.max(0, series.length - 5)];

  const change = current.value - fourWeeksAgo.value;
  const changePct = fourWeeksAgo.value > 0 ? (change / fourWeeksAgo.value) * 100 : 0;

  // Linear projection 4 weeks forward
  const indexed = series.map((s, i) => ({ x: i, y: s.value }));
  const { slope, intercept } = linearTrend(indexed);
  const projection4w = Math.round((intercept + slope * (series.length + 3)) * 10) / 10;

  const allBestSets = data.history.flatMap(s => s.sets.map(set => ({ ...set, date: s.date })));
  const heaviestSet = allBestSets.reduce((b, s) => s.weight > b.weight ? s : b, allBestSets[0]);

  return (
    <>
      {/* Main strength chart */}
      <div className={`${theme.card} rounded-2xl border ${theme.border} p-4`}>
        <div className="flex items-baseline gap-2 mb-1">
          <div className={`text-3xl font-bold ${theme.text}`}>{current.value.toFixed(1)}</div>
          <div className={`text-sm ${theme.textMuted}`}>kg</div>
        </div>
        <div className={`text-[11px] ${theme.textMuted} mb-2`}>Estimated 1RM</div>

        <div className="flex items-center gap-2 mb-3">
          <span className="text-xs font-bold flex items-center gap-0.5" style={{ color: change >= 0 ? GREEN : RED }}>
            {change >= 0 ? "▲" : "▼"} {Math.abs(change).toFixed(1)} kg ({Math.abs(changePct).toFixed(1)}%)
          </span>
          <span className={`text-[10px] ${theme.textMuted}`}>vs ~4 weeks ago</span>
        </div>

        <StrengthChart series={series} projection={{ slope, intercept, atEnd: projection4w }} theme={theme} />
      </div>

      {/* 1RM Projection + Best set */}
      <div className="grid grid-cols-2 gap-2">
        <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`}>
          <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted}`}>1RM Projection</div>
          <div className="flex items-baseline gap-1 mt-1">
            <div className="text-2xl font-bold" style={{ color: ORANGE }}>{projection4w.toFixed(1)}</div>
            <div className={`text-xs ${theme.textMuted}`}>kg</div>
          </div>
          <div className={`text-[10px] ${theme.textMuted} mt-0.5`}>in 4 weeks at current trend</div>
        </div>
        <div className={`${theme.card} rounded-2xl border ${theme.border} p-3`}>
          <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted}`}>Heaviest Set</div>
          <div className="flex items-baseline gap-1 mt-1">
            <div className={`text-2xl font-bold ${theme.text}`}>{heaviestSet.weight}</div>
            <div className={`text-xs ${theme.textMuted}`}>kg × {heaviestSet.reps}</div>
          </div>
          <div className={`text-[10px] ${theme.textMuted} mt-0.5`}>{new Date(heaviestSet.date).toLocaleDateString("en-GB", { day: "numeric", month: "short" })}</div>
        </div>
      </div>

      {/* Per-session breakdown */}
      <div className={`${theme.card} rounded-2xl border ${theme.border} p-4`}>
        <div className={`text-[10px] font-bold uppercase tracking-wide ${theme.textMuted} mb-3`}>Recent Sessions</div>
        <div className="space-y-1.5">
          {data.history.slice(-6).reverse().map((s, i) => {
            const totalVol = s.sets.reduce((sum, set) => sum + set.weight * set.reps, 0);
            const best1RM = s.sets.reduce((m, set) => Math.max(m, estimate1RM(set.weight, set.reps)), 0);
            return (
              <div key={i} className={`flex items-center justify-between py-2 ${i < data.history.slice(-6).length - 1 ? "border-b" : ""} ${theme.border}`}>
                <div>
                  <div className={`text-xs font-semibold ${theme.text}`}>{new Date(s.date).toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "short" })}</div>
                  <div className={`text-[10px] ${theme.textMuted}`}>{s.sets.length} sets · {Math.round(totalVol)} kg vol</div>
                </div>
                <div className="text-right">
                  <div className="text-sm font-bold" style={{ color: ORANGE }}>{best1RM.toFixed(1)} kg</div>
                  <div className={`text-[10px] ${theme.textMuted}`}>e1RM</div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </>
  );
}

function StrengthMiniChart({ exerciseName, lifts, theme }) {
  const data = lifts[exerciseName];
  if (!data?.history) return null;
  const series = data.history.map(s => ({
    date: s.date,
    value: s.sets.reduce((m, set) => Math.max(m, estimate1RM(set.weight, set.reps)), 0),
  }));
  const current = series[series.length - 1];
  const earliest = series[0];
  const change = current.value - earliest.value;
  const changePct = earliest.value > 0 ? (change / earliest.value) * 100 : 0;

  return (
    <>
      <div className="flex items-baseline gap-2 mb-1">
        <span className={`text-xl font-bold ${theme.text}`}>{current.value.toFixed(1)} kg</span>
        <span className={`text-[10px] ${theme.textMuted}`}>{exerciseName}</span>
      </div>
      <div className="flex items-center gap-1.5 mb-2">
        <span className="text-[11px] font-bold flex items-center gap-0.5" style={{ color: change >= 0 ? GREEN : RED }}>
          {change >= 0 ? "▲" : "▼"} {Math.abs(change).toFixed(1)} kg ({Math.abs(changePct).toFixed(1)}%)
        </span>
      </div>
      <StrengthChart series={series} mini theme={theme} />
    </>
  );
}

function StrengthChart({ series, projection, mini, theme }) {
  if (!series || series.length < 2) {
    return <div className={`text-xs ${theme.textMuted} text-center py-6`}>Need at least 2 sessions for chart</div>;
  }

  const w = 320;
  const h = mini ? 100 : 180;
  const pad = { top: 10, right: 16, bottom: 24, left: 32 };
  const cw = w - pad.left - pad.right;
  const ch = h - pad.top - pad.bottom;

  const values = series.map(s => s.value);
  const minV = Math.floor(Math.min(...values) * 0.95);
  const maxV = Math.ceil(Math.max(...values) * 1.05);
  const range = maxV - minV || 1;

  const points = series.map((s, i) => {
    const x = pad.left + (i / (series.length - 1)) * cw;
    const y = pad.top + (1 - (s.value - minV) / range) * ch;
    return { x, y, ...s };
  });

  const linePts = points.map(p => `${p.x},${p.y}`).join(" ");
  const areaPts = `${pad.left},${pad.top + ch} ${linePts} ${pad.left + cw},${pad.top + ch}`;

  // Trend line
  const trendStart = projection ? projection.intercept : null;
  const trendEnd = projection ? projection.intercept + projection.slope * (series.length - 1) : null;

  // Y-axis labels
  const yLabels = mini ? [] : [minV, Math.round((minV + maxV) / 2), maxV];

  // X-axis labels (start, mid, end)
  const xLabels = series.length > 1 ? [
    { idx: 0, date: series[0].date },
    { idx: Math.floor(series.length / 2), date: series[Math.floor(series.length / 2)].date },
    { idx: series.length - 1, date: series[series.length - 1].date },
  ] : [];

  return (
    <svg viewBox={`0 0 ${w} ${h}`} width="100%" height={mini ? 80 : "auto"}>
      <defs>
        <linearGradient id="strengthGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={ORANGE} stopOpacity="0.4" />
          <stop offset="100%" stopColor={ORANGE} stopOpacity="0" />
        </linearGradient>
      </defs>

      {/* Grid lines */}
      {!mini && yLabels.map((v, i) => {
        const y = pad.top + (1 - (v - minV) / range) * ch;
        return <line key={i} x1={pad.left} y1={y} x2={pad.left + cw} y2={y} stroke={theme.chartGrid} strokeWidth="0.5" strokeDasharray="2,2" />;
      })}

      {/* Trend line (dashed) */}
      {!mini && projection && (
        <line
          x1={pad.left} y1={pad.top + (1 - (trendStart - minV) / range) * ch}
          x2={pad.left + cw} y2={pad.top + (1 - (trendEnd - minV) / range) * ch}
          stroke={theme.textMuted.includes("400") ? "#475569" : "#94a3b8"} strokeWidth="1" strokeDasharray="3,3"
        />
      )}

      {/* Area */}
      <polygon points={areaPts} fill="url(#strengthGrad)" />
      {/* Line */}
      <polyline fill="none" stroke={ORANGE} strokeWidth="2" points={linePts} strokeLinejoin="round" />
      {/* Dots */}
      {points.map((p, i) => (
        <circle key={i} cx={p.x} cy={p.y} r={i === points.length - 1 ? 4 : 2.5}
          fill={i === points.length - 1 ? ORANGE : theme.bg.includes("black") ? "#0f172a" : "white"}
          stroke={ORANGE} strokeWidth="1.5" />
      ))}
      {/* Final value badge */}
      {!mini && (
        <g>
          <rect
            x={points[points.length - 1].x - 22}
            y={points[points.length - 1].y - 22}
            width="40" height="16" rx="3"
            fill={ORANGE} />
          <text x={points[points.length - 1].x - 2} y={points[points.length - 1].y - 10}
            fontSize="10" fontWeight="bold" fill="white" textAnchor="middle">
            {points[points.length - 1].value.toFixed(1)}
          </text>
        </g>
      )}

      {/* Y labels */}
      {yLabels.map((v, i) => {
        const y = pad.top + (1 - (v - minV) / range) * ch;
        return <text key={i} x={pad.left - 6} y={y + 3} fontSize="9" fill={theme.textMuted.includes("400") ? "#64748b" : "#94a3b8"} textAnchor="end">{v}</text>;
      })}

      {/* X labels */}
      {!mini && xLabels.map((l, i) => {
        const x = pad.left + (l.idx / (series.length - 1)) * cw;
        return (
          <text key={i} x={x} y={h - 8} fontSize="9" fill={theme.textMuted.includes("400") ? "#64748b" : "#94a3b8"} textAnchor="middle">
            {new Date(l.date).toLocaleDateString("en-GB", { day: "numeric", month: "short" })}
          </text>
        );
      })}
    </svg>
  );
}

